+            Err(mpsc::RecvError::Empty) => {
+                // Park briefly to avoid busy-waiting under no-load.
+                std::thread::sleep(std::time::Duration::from_millis(1));
+            }
+            Err(mpsc::RecvError::Disconnected) | Err(mpsc::RecvError::Cancelled) => {
+                break 'main;
+            }
         }
